LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;

ENTITY my_module IS
  PORT ( a : IN STD_LOGIC; b : OUT STD_LOGIC );
END my_module;

ARCHITECTURE behavior OF my_module IS
BEGIN
  b <= NOT a;
END behavior;

hdl_code.vhdl:
entity half_adder is
 port(a, b: in bit; sum, carry: out bit);
end half_adder;
architecture dataflow of half_adder is
begin
 sum <= a xor b;
 carry <= a and b;
end dataflow;

hdl_code.verilog:
// Equivalent Verilog
module half_adder(input a, b, output sum, carry);
 assign sum = a ^ b;
 assign carry = a & b;
endmodule

examples.code:
module dff(input clk, rst, d, output reg q);
  always @(posedge clk or posedge rst)
    if (rst) q <= 0;
    else     q <= d;
endmodule

module counter4bit(input clk, rst, output reg [3:0] count);
  always @(posedge clk or posedge rst)
    if (rst) count <= 4'b0000;
    else     count <= count + 1;
endmodule

module fifo #(parameter DEPTH=8, WIDTH=8)(
  input clk, rst, wr_en, rd_en,
  input [WIDTH-1:0] din,
  output reg [WIDTH-1:0] dout,
  output full, empty
);
  reg [WIDTH-1:0] mem [0:DEPTH-1];
  reg [2:0] wr_ptr, rd_ptr;
  reg [3:0] cnt;
  assign full  = (cnt == DEPTH);
  assign empty = (cnt == 0);
  always @(posedge clk or posedge rst) begin
    if (rst) begin wr_ptr<=0; rd_ptr<=0; cnt<=0; end
    else begin
      if (wr_en && !full)  begin mem[wr_ptr]<=din; wr_ptr<=wr_ptr+1; cnt<=cnt+1; end
      if (rd_en && !empty) begin dout<=mem[rd_ptr]; rd_ptr<=rd_ptr+1; cnt<=cnt-1; end
    end
  end
endmodule

