module decoder2to4(input A, B, output Y0, Y1, Y2, Y3);
  assign Y0 = ~A & ~B;
  assign Y1 = ~A &  B;
  assign Y2 =  A & ~B;
  assign Y3 =  A &  B;
endmodule
